117	            RBTDRM_COLOPHON_QUENCH,
118	            RBTDRM_COLOPHON_WRIT,
119	            RBTDRM_COLOPHON_FIAT,
120	            RBTDRM_COLOPHON_BARK,
121	            RBTDRM_COLOPHON_CRUCIBLE_ACTIVE,
122	        ]),
123	        RBTDRM_FIXTURE_FOUR_MODE => Some(&[
124	            RBTDRM_COLOPHON_ORDAIN,
125	            RBTDRM_COLOPHON_ABJURE,
126	            RBTDRM_COLOPHON_WREST_HALLMARK_IMAGE,
127	            RBTDRM_COLOPHON_KLUDGE,
128	            RBTDRM_COLOPHON_SUMMON,
129	            RBTDRM_COLOPHON_PLUMB_FULL,
130	            RBTDRM_COLOPHON_PLUMB_COMPACT,
131	            RBTDRM_COLOPHON_REKON_HALLMARK,
132	            RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE,
133	        ]),
134	        RBTDRM_FIXTURE_BATCH_VOUCH => Some(&[
135	            RBTDRM_COLOPHON_ORDAIN,
136	            RBTDRM_COLOPHON_ABJURE,
137	            RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE,
138	            RBTDRM_COLOPHON_VOUCH,
139	            RBTDRM_COLOPHON_TALLY,
140	        ]),
141	        RBTDRM_FIXTURE_ACCESS_PROBE => Some(&[RBTDRM_COLOPHON_ACCESS_PROBE]),
142	        RBTDRM_FIXTURE_ENROLLMENT_VALIDATION
143	        | RBTDRM_FIXTURE_REGIME_VALIDATION
144	        | RBTDRM_FIXTURE_REGIME_SMOKE => Some(&[]),
145	        RBTDRM_FIXTURE_PRISTINE_LIFECYCLE => Some(&[
146	            RBTDRM_COLOPHON_DEPOT_LEVY,
147	            RBTDRM_COLOPHON_DEPOT_LIST,
148	            RBTDRM_COLOPHON_DEPOT_UNMAKE,
149	            RBTDRM_COLOPHON_GOV_MANTLE,
150	            RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
151	            RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR,
152	            RBTDRM_COLOPHON_GOV_DIVEST_RETRIEVER,
153	            RBTDRM_COLOPHON_GOV_DIVEST_DIRECTOR,
154	            RBTDRM_COLOPHON_ACCESS_PROBE,
155	        ]),
156	        RBTDRM_FIXTURE_CANONICAL_ESTABLISH => Some(&[
157	            RBTDRM_COLOPHON_DEPOT_LEVY,
158	            RBTDRM_COLOPHON_DEPOT_LIST,
159	            RBTDRM_COLOPHON_GOV_MANTLE,
160	            RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
