81	// ── Helpers ──────────────────────────────────────────────────
82	
83	/// Read an env-file value or None if absent. Mirrors pristine's helper —
84	/// kept local to avoid coupling canonical-establish to pristine-lifecycle.
85	fn rbtdrk_read_env_value(path: &Path, key: &str) -> Option<String> {
86	    let content = std::fs::read_to_string(path).ok()?;
87	    let prefix = format!("{}=", key);
88	    for line in content.lines() {
89	        let trimmed = line.trim_start();
90	        if trimmed.starts_with('#') {
91	            continue;
92	        }
93	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
94	            return Some(rest.to_string());
95	        }
96	    }
97	    None
98	}
99	
100	fn rbtdrk_resolve(root: &Path, raw: &str) -> PathBuf {
101	    if Path::new(raw).is_absolute() {
102	        PathBuf::from(raw)
103	    } else {
104	        root.join(raw)
105	    }
106	}
107	
108	fn rbtdrk_replace_env_fields(content: &str, pairs: &[(&str, &str)]) -> String {
109	    let mut result: String = content
110	        .lines()
111	        .map(|line| {
112	            for (key, value) in pairs {
113	                let assign = format!("{}=", key);
114	                if line.starts_with(&assign) {
115	                    return format!("{}{}", assign, value);
116	                }
117	            }
118	            line.to_string()
119	        })
120	        .collect::<Vec<_>>()
121	        .join("\n");
122	    if content.ends_with('\n') {
123	        result.push('\n');
124	    }
125	    result
126	}
127	
128	fn rbtdrk_git_add_and_commit(root: &Path, file: &str, message: &str) -> Result<(), String> {
129	    let add = Command::new("git")
130	        .args(["add", file])
131	        .current_dir(root)
132	        .output()
133	        .map_err(|e| format!("rbtdrk: git add invocation failed: {}", e))?;
134	    if !add.status.success() {
135	        return Err(format!(
136	            "rbtdrk: git add failed (exit {}): {}",
137	            add.status.code().unwrap_or(-1),
138	            String::from_utf8_lossy(&add.stderr).trim()
139	        ));
140	    }
141	    let commit = Command::new("git")
142	        .args(["commit", "-m", message])
143	        .current_dir(root)
144	        .output()
145	        .map_err(|e| format!("rbtdrk: git commit invocation failed: {}", e))?;
146	    if !commit.status.success() {
147	        return Err(format!(
148	            "rbtdrk: git commit failed (exit {}): {}",
149	            commit.status.code().unwrap_or(-1),
150	            String::from_utf8_lossy(&commit.stderr).trim()
151	        ));
152	    }
153	    Ok(())
154	}
155	
156	/// Resolve canonical RBRA path for a role: <RBRR_SECRETS_DIR>/<role>/rbra.env.
157	fn rbtdrk_canonical_rbra(root: &Path, role: &str) -> Result<PathBuf, String> {
158	    let rbrr = root.join(RBTDRK_RBRR_FILE);
159	    let secrets_dir = rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_SECRETS_DIR)
160	        .ok_or_else(|| format!("RBRR_SECRETS_DIR missing from {}", rbrr.display()))?;
161	    if secrets_dir.is_empty() {
162	        return Err(format!("RBRR_SECRETS_DIR is blank in {}", rbrr.display()));
163	    }
164	    Ok(rbtdrk_resolve(root, &secrets_dir)
165	        .join(role)
166	        .join(RBTDRK_RBRA_FILE))
167	}
168	
169	// ── Canonical-prefix install (case 1) ───────────────────────
170	
171	/// Idempotently install canc-/canr- prefixes into rbrr.env. Returns Ok
172	/// without committing when prefixes already match the canonical markers;
173	/// otherwise rewrites both lines and commits.
174	pub(crate) fn rbtdrk_install_canonical_prefixes(root: &Path) -> Result<(), String> {
175	    let rbrr = root.join(RBTDRK_RBRR_FILE);
176	    let cloud = rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_CLOUD_PREFIX).unwrap_or_default();
177	    let runtime =
178	        rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_RUNTIME_PREFIX).unwrap_or_default();
179	    if cloud == RBTDRK_CANONICAL_CLOUD_PREFIX && runtime == RBTDRK_CANONICAL_RUNTIME_PREFIX {
180	        return Ok(());
181	    }
182	    let content = std::fs::read_to_string(&rbrr)
183	        .map_err(|e| format!("rbtdrk: read {}: {}", rbrr.display(), e))?;
184	    let new_content = rbtdrk_replace_env_fields(
185	        &content,
186	        &[
187	            (
188	                RBTDRK_FIELD_RBRR_CLOUD_PREFIX,
189	                RBTDRK_CANONICAL_CLOUD_PREFIX,
190	            ),
191	            (
192	                RBTDRK_FIELD_RBRR_RUNTIME_PREFIX,
193	                RBTDRK_CANONICAL_RUNTIME_PREFIX,
194	            ),
195	        ],
196	    );
197	    std::fs::write(&rbrr, &new_content)
198	        .map_err(|e| format!("rbtdrk: write {}: {}", rbrr.display(), e))?;
199	    let commit_msg = format!(
200	        "canonical-establish fixture: install canonical RBRR prefixes ({}/{})",
201	        RBTDRK_CANONICAL_CLOUD_PREFIX, RBTDRK_CANONICAL_RUNTIME_PREFIX
202	    );
203	    rbtdrk_git_add_and_commit(root, RBTDRK_RBRR_FILE, &commit_msg)
204	}
205	
206	fn rbtdrk_install_depot_moniker(root: &Path, moniker: &str) -> Result<(), String> {
207	    let rbrr = root.join(RBTDRK_RBRR_FILE);
208	    let content = std::fs::read_to_string(&rbrr)
209	        .map_err(|e| format!("rbtdrk: read {}: {}", rbrr.display(), e))?;
210	    let new_content =
211	        rbtdrk_replace_env_fields(&content, &[(RBTDRK_FIELD_RBRR_DEPOT_MONIKER, moniker)]);
212	    std::fs::write(&rbrr, &new_content)
213	        .map_err(|e| format!("rbtdrk: write {}: {}", rbrr.display(), e))?;
214	    let commit_msg = format!(
215	        "canonical-establish fixture: set {}={}",
216	        RBTDRK_FIELD_RBRR_DEPOT_MONIKER, moniker
217	    );
218	    rbtdrk_git_add_and_commit(root, RBTDRK_RBRR_FILE, &commit_msg)
219	}
220	
221	/// Compose depot project_id from kindled regime values: <CLOUD>d-<moniker>.
222	fn rbtdrk_compose_project_id(root: &Path, moniker: &str) -> Result<String, String> {
223	    let rbrr = root.join(RBTDRK_RBRR_FILE);
224	    let cloud_prefix = rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_CLOUD_PREFIX)
225	        .ok_or_else(|| format!("RBRR_CLOUD_PREFIX missing from {}", rbrr.display()))?;
226	    Ok(format!("{}d-{}", cloud_prefix, moniker))
227	}
228	
229	/// Pick the next free moniker for `family_stem` by walking the depot_list
230	/// invocation's BURV output dir for `<family>NNNNNN.depot` files. Returns
231	/// `<family>RBTDRK_FAMILY_NUMERIC_FLOOR` when no matching files exist.
232	fn rbtdrk_pick_next_moniker(
233	    list_result: &rbtdri_InvokeResult,
234	    family_stem: &str,
235	) -> Result<String, String> {
236	    let dir = list_result.burv_output.join(RBTDRI_BURV_OUTPUT_SUBDIR);
237	    let entries = match std::fs::read_dir(&dir) {
238	        Ok(e) => e,
239	        Err(_) => {
240	            return Ok(format!("{}{}", family_stem, RBTDRK_FAMILY_NUMERIC_FLOOR));
241	        }
242	    };
243	    let suffix_ext = format!(".{}", RBTDRK_FACT_EXT_DEPOT);
244	    let mut max_suffix: Option<u32> = None;
245	    for entry in entries.flatten() {
246	        let name = match entry.file_name().into_string() {
247	            Ok(n) => n,
248	            Err(_) => continue,
249	        };
250	        let stem = match name.strip_suffix(&suffix_ext) {
251	            Some(s) => s,
252	            None => continue,
253	        };
254	        let numeric = match stem.strip_prefix(family_stem) {
255	            Some(s) => s,
256	            None => continue,
257	        };
258	        if numeric.len() != RBTDRK_FAMILY_NUMERIC_WIDTH {
259	            continue;
260	        }
261	        let parsed: u32 = match numeric.parse() {
262	            Ok(n) => n,
263	            Err(_) => continue,
264	        };
265	        max_suffix = Some(max_suffix.map_or(parsed, |m| m.max(parsed)));
266	    }
267	    let next = match max_suffix {
268	        Some(m) => m + 1,
269	        None => RBTDRK_FAMILY_NUMERIC_FLOOR,
270	    };
271	    Ok(format!("{}{}", family_stem, next))
272	}
273	
274	fn rbtdrk_invoke_logged(
275	    ctx: &mut rbtdri_Context,
276	    colophon: &str,
277	    args: &[&str],
278	    extra_env: &[(&str, &str)],
279	    dir: &Path,
280	    label: &str,
281	) -> Result<rbtdri_InvokeResult, String> {
282	    let result = rbtdri_invoke_global(ctx, colophon, args, extra_env)?;
283	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &result.stdout);
284	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &result.stderr);
285	    Ok(result)
286	}
287	
288	// ── Probes ───────────────────────────────────────────────────
289	
290	/// Probes are pure `fn() -> Result<(), String>` per the rbtdrb_Probe shape and
291	/// have no context, so they read the project root from current_dir() — theurge
292	/// always launches from the project root.
293	fn rbtdrk_probe_root() -> Result<PathBuf, String> {
294	    std::env::current_dir().map_err(|e| format!("cannot resolve project root: {}", e))
295	}
296	
297	/// Case 1 probe: rbrr.env exists. Sanity precondition — canonical-establish
298	/// presumes the regime has been initialized at least to the marshal-zero
299	/// blank-template shape.
300	fn rbtdrk_probe_rbrr_present() -> Result<(), String> {
301	    let root = rbtdrk_probe_root()?;
302	    let rbrr = root.join(RBTDRK_RBRR_FILE);
303	    if !rbrr.exists() {
304	        return Err(format!("rbrr.env not found at {}", rbrr.display()));
305	    }
306	    Ok(())
307	}
308	
309	/// Case 2 probe: canonical depot moniker installed in rbrr.env. Established
310	/// by case 1; absence means depot-levy didn't run or rbrr.env was rewritten.
311	fn rbtdrk_probe_canonical_moniker() -> Result<(), String> {
312	    let root = rbtdrk_probe_root()?;
313	    let rbrr = root.join(RBTDRK_RBRR_FILE);
314	    let moniker =
315	        rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_DEPOT_MONIKER).unwrap_or_default();
316	    if !moniker.starts_with(RBTDRK_FAMILY_STEM) {
317	        return Err(format!(
318	            "{}={:?} does not begin with '{}' — canonical depot moniker not installed",
319	            RBTDRK_FIELD_RBRR_DEPOT_MONIKER, moniker, RBTDRK_FAMILY_STEM
320	        ));
321	    }
322	    Ok(())
323	}
324	
325	/// Cases 3 and 4 probe: governor RBRA file present at the canonical path.
326	/// Established by case 2's mantle + canonical-copy step.
327	fn rbtdrk_probe_governor_rbra() -> Result<(), String> {
328	    let root = rbtdrk_probe_root()?;
329	    let path = rbtdrk_canonical_rbra(&root, "governor")?;
330	    if !path.exists() {
331	        return Err(format!("governor RBRA absent at {}", path.display()));
332	    }
333	    Ok(())
334	}
335	
336	// ── Cases ────────────────────────────────────────────────────
337	
338	/// Case 1 — canonical depot levy. Installs canc-/canr- prefixes, picks a
339	/// fresh canest moniker, levies the depot, cross-checks project_id from
340	/// fact-file against the RBDC compose derivation.
341	fn rbtdrk_depot_levy(dir: &Path) -> rbtdre_Verdict {
342	    let probe = rbtdrb_Probe {
343	        name: "rbrr.env present",
344	        check: rbtdrk_probe_rbrr_present,
345	        remediation: "ensure regime is initialized — rerun pristine-lifecycle if needed",
346	    };
347	    if let Err(v) = rbtdrb_assert(&probe) {
348	        return v;
349	    }
350	    rbtdrc_with_ctx(|ctx| rbtdrk_depot_levy_impl(ctx, dir))
351	}
352	
353	fn rbtdrk_depot_levy_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
354	    let root = ctx.project_root().to_path_buf();
355	
356	    if let Err(e) = rbtdrk_install_canonical_prefixes(&root) {
357	        return rbtdre_Verdict::Fail(format!("install canonical prefixes: {}", e));
358	    }
359	
360	    let list_pre = match rbtdrk_invoke_logged(
361	        ctx,
362	        RBTDRM_COLOPHON_DEPOT_LIST,
363	        &[],
364	        &[],
365	        dir,
366	        "list-pre",
367	    ) {
368	        Ok(r) => r,
369	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (pre-levy): {}", e)),
370	    };
371	    if list_pre.exit_code != 0 {
372	        return rbtdre_Verdict::Fail(format!(
373	            "depot list (pre-levy) exit {}\n{}",
374	            list_pre.exit_code, list_pre.stderr
375	        ));
376	    }
377	
378	    let moniker = match rbtdrk_pick_next_moniker(&list_pre, RBTDRK_FAMILY_STEM) {
379	        Ok(m) => m,
380	        Err(e) => return rbtdre_Verdict::Fail(format!("pick next moniker: {}", e)),
381	    };
382	    if let Err(e) = rbtdrk_install_depot_moniker(&root, &moniker) {
383	        return rbtdre_Verdict::Fail(format!("install depot moniker: {}", e));
384	    }
385	
386	    let levy = match rbtdrk_invoke_logged(
387	        ctx,
388	        RBTDRM_COLOPHON_DEPOT_LEVY,
389	        &[],
390	        &[],
391	        dir,
392	        "levy",
393	    ) {
394	        Ok(r) => r,
395	        Err(e) => return rbtdre_Verdict::Fail(format!("depot levy: {}", e)),
396	    };
397	    if levy.exit_code != 0 {
398	        return rbtdre_Verdict::Fail(format!(
399	            "depot levy exit {}\n{}",
400	            levy.exit_code, levy.stderr
401	        ));
402	    }
403	
404	    let list_present = match rbtdrk_invoke_logged(
405	        ctx,
406	        RBTDRM_COLOPHON_DEPOT_LIST,
407	        &[],
408	        &[],
409	        dir,
410	        "list-present",
411	    ) {
412	        Ok(r) => r,
413	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after levy): {}", e)),
414	    };
415	    if list_present.exit_code != 0 {
416	        return rbtdre_Verdict::Fail(format!(
417	            "depot list (after levy) exit {}\n{}",
418	            list_present.exit_code, list_present.stderr
419	        ));
420	    }
421	
422	    let fact_path = list_present
423	        .burv_output
424	        .join(RBTDRI_BURV_OUTPUT_SUBDIR)
425	        .join(format!("{}.{}", moniker, RBTDRK_FACT_EXT_DEPOT_PROJECT));
426	    let fact_project_id = match std::fs::read_to_string(&fact_path) {
427	        Ok(s) => s.trim().to_string(),
428	        Err(e) => {
429	            return rbtdre_Verdict::Fail(format!(
430	                "read depot-project fact '{}': {}",
431	                fact_path.display(),
432	                e
433	            ))
434	        }
435	    };
436	    if fact_project_id.is_empty() {
437	        return rbtdre_Verdict::Fail(format!(
438	            "depot-project fact is empty: {}",
439	            fact_path.display()
440	        ));
441	    }
442	    let _ = std::fs::write(dir.join("project-id.txt"), &fact_project_id);
443	
444	    let composed = match rbtdrk_compose_project_id(&root, &moniker) {
445	        Ok(p) => p,
446	        Err(e) => return rbtdre_Verdict::Fail(format!("compose project_id: {}", e)),
447	    };
448	    if composed != fact_project_id {
449	        return rbtdre_Verdict::Fail(format!(
450	            "project_id mismatch: RBDC compose='{}' vs depot-list fact='{}' \
451	             (RBDC kindle derivation diverged from payor creation)",
452	            composed, fact_project_id
453	        ));
454	    }
455	    rbtdre_Verdict::Pass
456	}
457	
458	/// Case 2 — governor mantle. Mantles governor against the canonical depot,
459	/// reads the SA email fact, copies governor RBRA from BURV output to the
460	/// canonical path under RBRR_SECRETS_DIR.
461	fn rbtdrk_governor_mantle(dir: &Path) -> rbtdre_Verdict {
462	    let probe = rbtdrb_Probe {
463	        name: "canonical depot moniker installed",
464	        check: rbtdrk_probe_canonical_moniker,
465	        remediation: "rerun rbtdrk_depot_levy or the full canonical-establish fixture",
466	    };
467	    if let Err(v) = rbtdrb_assert(&probe) {
468	        return v;
469	    }
470	    rbtdrc_with_ctx(|ctx| rbtdrk_governor_mantle_impl(ctx, dir))
471	}
472	
473	fn rbtdrk_governor_mantle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
474	    let root = ctx.project_root().to_path_buf();
475	
476	    let mantle = match rbtdrk_invoke_logged(
477	        ctx,
478	        RBTDRM_COLOPHON_GOV_MANTLE,
479	        &[],
480	        &[],
481	        dir,
482	        "mantle",
483	    ) {
484	        Ok(r) => r,
485	        Err(e) => return rbtdre_Verdict::Fail(format!("governor mantle: {}", e)),
486	    };
487	    if mantle.exit_code != 0 {
488	        return rbtdre_Verdict::Fail(format!(
489	            "governor mantle exit {}\n{}",
490	            mantle.exit_code, mantle.stderr
491	        ));
492	    }
493	
494	    let email = match rbtdri_read_burv_fact(&mantle, RBTDRK_FACT_GOVERNOR_SA_EMAIL) {
495	        Ok(s) => s,
496	        Err(e) => return rbtdre_Verdict::Fail(format!("read governor SA email fact: {}", e)),
497	    };
498	    let _ = std::fs::write(dir.join("governor-sa-email.txt"), &email);
499	
500	    let mantle_out_dir = mantle.burv_output.join(RBTDRI_BURV_OUTPUT_SUBDIR);
501	    let governor_rbra_src = match std::fs::read_dir(&mantle_out_dir)
502	        .map_err(|e| format!("read mantle output dir {}: {}", mantle_out_dir.display(), e))
503	        .and_then(|entries| {
504	            let matches: Vec<_> = entries
505	                .filter_map(|e| e.ok())
506	                .filter(|e| {
507	                    e.file_name()
508	                        .to_str()
509	                        .map(|n| n.starts_with("governor-") && n.ends_with(".rbra"))
510	                        .unwrap_or(false)
511	                })
512	                .collect();
513	            match matches.len() {
514	                0 => Err("no governor-*.rbra file in mantle BURV output".to_string()),
515	                1 => Ok(matches.into_iter().next().unwrap().path()),
516	                n => Err(format!("{} governor-*.rbra files in mantle BURV output", n)),
517	            }
518	        }) {
519	        Ok(p) => p,
520	        Err(e) => return rbtdre_Verdict::Fail(format!("locate governor RBRA: {}", e)),
521	    };
522	
523	    let canonical = match rbtdrk_canonical_rbra(&root, "governor") {
524	        Ok(p) => p,
525	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical governor RBRA path: {}", e)),
526	    };
527	    if let Some(parent) = canonical.parent() {
528	        if let Err(e) = std::fs::create_dir_all(parent) {
529	            return rbtdre_Verdict::Fail(format!(
530	                "create governor RBRA dir {}: {}",
531	                parent.display(),
532	                e
533	            ));
534	        }
535	    }
536	    if let Err(e) = std::fs::copy(&governor_rbra_src, &canonical) {
537	        return rbtdre_Verdict::Fail(format!(
538	            "copy governor RBRA {} → {}: {}",
539	            governor_rbra_src.display(),
540	            canonical.display(),
541	            e
542	        ));
543	    }
544	    if !canonical.exists() {
545	        return rbtdre_Verdict::Fail(format!(
546	            "governor canonical RBRA absent after copy: {}",
547	            canonical.display()
548	        ));
549	    }
550	    rbtdre_Verdict::Pass
551	}
552	
553	/// Case 3 — retriever invest + access-probe. The access-probe doubles as the
554	/// IAM-propagation gate: the invest tabtarget is responsible for waiting on
555	/// propagation before exiting (or the probe iterates internally). No separate
556	/// propagation-wait case.
557	fn rbtdrk_retriever_invest(dir: &Path) -> rbtdre_Verdict {
558	    let probe = rbtdrb_Probe {
559	        name: "governor RBRA present",
560	        check: rbtdrk_probe_governor_rbra,
561	        remediation: "rerun rbtdrk_governor_mantle or the full canonical-establish fixture",
562	    };
563	    if let Err(v) = rbtdrb_assert(&probe) {
564	        return v;
565	    }
566	    rbtdrc_with_ctx(|ctx| {
567	        rbtdrk_role_invest_impl(
568	            ctx,
569	            dir,
570	            RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
571	            RBTDRK_IDENTITY_RETRIEVER,
572	            "retriever",
573	        )
574	    })
575	}
576	
577	/// Case 4 — director invest + access-probe.
578	fn rbtdrk_director_invest(dir: &Path) -> rbtdre_Verdict {
579	    let probe = rbtdrb_Probe {
580	        name: "governor RBRA present",
581	        check: rbtdrk_probe_governor_rbra,
582	        remediation: "rerun rbtdrk_governor_mantle or the full canonical-establish fixture",
583	    };
584	    if let Err(v) = rbtdrb_assert(&probe) {
585	        return v;
586	    }
587	    rbtdrc_with_ctx(|ctx| {
588	        rbtdrk_role_invest_impl(
589	            ctx,
590	            dir,
591	            RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR,
592	            RBTDRK_IDENTITY_DIRECTOR,
593	            "director",
594	        )
595	    })
596	}
597	
598	/// Shared invest body for retriever and director: invest → assert assay
599	/// dropped by the invest tabtarget → copy to canonical role path → access-probe.
600	fn rbtdrk_role_invest_impl(
601	    ctx: &mut rbtdri_Context,
602	    dir: &Path,
603	    invest_colophon: &str,
604	    identity: &str,
605	    role: &str,
606	) -> rbtdre_Verdict {
607	    let root = ctx.project_root().to_path_buf();
608	
609	    let assay = match rbtdrk_canonical_rbra(&root, "assay") {
610	        Ok(p) => p,
611	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical assay RBRA path: {}", e)),
612	    };
613	
614	    let label_invest = format!("invest-{}", role);
615	    let invest = match rbtdrk_invoke_logged(
616	        ctx,
617	        invest_colophon,
618	        &[identity],
619	        &[],
620	        dir,
621	        &label_invest,
622	    ) {
623	        Ok(r) => r,
624	        Err(e) => return rbtdre_Verdict::Fail(format!("invest {}: {}", role, e)),
625	    };
626	    if invest.exit_code != 0 {
627	        return rbtdre_Verdict::Fail(format!(
628	            "invest {} exit {}\n{}",
629	            role, invest.exit_code, invest.stderr
630	        ));
631	    }
632	
633	    if !assay.exists() {
634	        return rbtdre_Verdict::Fail(format!(
635	            "assay RBRA absent after invest-{}: {}",
636	            role,
637	            assay.display()
638	        ));
639	    }
640	
641	    let canonical = match rbtdrk_canonical_rbra(&root, role) {
642	        Ok(p) => p,
643	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical {} RBRA path: {}", role, e)),
644	    };
645	    if let Some(parent) = canonical.parent() {
646	        if let Err(e) = std::fs::create_dir_all(parent) {
647	            return rbtdre_Verdict::Fail(format!(
648	                "create {} RBRA dir {}: {}",
649	                role,
650	                parent.display(),
651	                e
652	            ));
653	        }
654	    }
655	    if let Err(e) = std::fs::copy(&assay, &canonical) {
656	        return rbtdre_Verdict::Fail(format!(
657	            "copy assay RBRA → {} canonical {}: {}",
658	            role,
659	            canonical.display(),
660	            e
661	        ));
662	    }
663	
664	    let probe_result = match rbtdri_invoke_imprint(ctx, RBTDRM_COLOPHON_ACCESS_PROBE, role, &[]) {
665	        Ok(r) => r,
666	        Err(e) => {
667	            return rbtdre_Verdict::Fail(format!("access-probe {} invocation: {}", role, e))
668	        }
669	    };
670	    let _ = std::fs::write(
671	        dir.join(format!("probe-{}-stdout.txt", role)),
672	        &probe_result.stdout,
673	    );
674	    let _ = std::fs::write(
675	        dir.join(format!("probe-{}-stderr.txt", role)),
676	        &probe_result.stderr,
677	    );
678	    if probe_result.exit_code != 0 {
679	        return rbtdre_Verdict::Fail(format!(
680	            "access-probe {} exit {}\n{}",
681	            role, probe_result.exit_code, probe_result.stderr
682	        ));
683	    }
684	
685	    rbtdre_Verdict::Pass
686	}
687	
688	// ── Section registry ─────────────────────────────────────────
689	
690	pub static RBTDRK_SECTIONS_CANONICAL_ESTABLISH: &[rbtdre_Section] = &[rbtdre_Section {
691	    name: "canonical-establish-arc",
692	    cases: &[
693	        case!(rbtdrk_depot_levy),
694	        case!(rbtdrk_governor_mantle),
695	        case!(rbtdrk_retriever_invest),
696	        case!(rbtdrk_director_invest),
697	    ],
698	}];
