16	//
17	// RBTDRE — case execution engine for theurge
18	
19	use std::path::Path;
20	use std::path::PathBuf;
21	
22	// ── Verdict ────────────────────────────────────────────────────
23	
24	/// Verdict from a single test case execution.
25	pub enum rbtdre_Verdict {
26	    Pass,
27	    Fail(String),
28	    Skip(String),
29	}
30	
31	// ── Disposition ────────────────────────────────────────────────
32	
33	/// Fixture disposition controls per-fixture mode policy at the engine layer.
34	///
35	/// `Independent` — cases are self-contained; suite-order is informational. Engine
36	/// permits keep-going mode for surveying.
37	///
38	/// `StateProgressing` — case N's success establishes preconditions for case N+1.
39	/// Engine refuses keep-going mode (a failed case leaves a broken precondition for
40	/// the next case, so continuing is incoherent). Fail-fast is forced.
41	#[derive(Copy, Clone, PartialEq, Eq, Debug)]
42	pub enum rbtdre_Disposition {
43	    Independent,
44	    StateProgressing,
45	}
46	
47	/// Resolve the effective fail-fast bool from a disposition and a caller's
48	/// requested keep-going mode. Returns Err if the request is incompatible with
49	/// the disposition (StateProgressing + keep-going).
50	///
51	/// Centralizes the keep-going / fail-fast policy at the engine boundary so all
52	/// callers funnel through one place.
53	pub fn rbtdre_resolve_fail_fast(
54	    disposition: rbtdre_Disposition,
55	    keep_going_requested: bool,
56	) -> Result<bool, String> {
57	    match (disposition, keep_going_requested) {
58	        (rbtdre_Disposition::StateProgressing, true) => Err(
59	            "rbtd: keep-going mode refused for StateProgressing fixture — \
60	             a failed case leaves a broken precondition for the next case, \
61	             so continuing is incoherent. Run individual cases via the \
62	             SingleCase tabtarget if you want to survey."
63	                .to_string(),
64	        ),
65	        (rbtdre_Disposition::StateProgressing, false) => Ok(true),
66	        (rbtdre_Disposition::Independent, keep_going) => Ok(!keep_going),
67	    }
68	}
69	
70	// ── Case and Section ───────────────────────────────────────────
71	
72	/// A named test case with a function that receives its isolated temp directory.
73	/// The `name` field holds the raw stringified function name (from the `case!` macro).
74	pub struct rbtdre_Case {
75	    pub name: &'static str,
76	    pub func: fn(&Path) -> rbtdre_Verdict,
77	}
78	
79	/// A named group of test cases, printed as a section header during execution.
80	pub struct rbtdre_Section {
81	    pub name: &'static str,
82	    pub cases: &'static [rbtdre_Case],
83	}
84	
85	/// Case registration macro. Derives case name from function name via `stringify!`.
86	/// Compiler enforces uniqueness — duplicate function names won't compile.
87	#[macro_export]
88	macro_rules! case {
89	    ($func:path) => {
90	        $crate::rbtdre_engine::rbtdre_Case {
91	            name: stringify!($func),
92	            func: $func,
93	        }
94	    };
95	}
96	
97	// ── Colors ─────────────────────────────────────────────────────
98	
99	/// Terminal color codes, empty strings when color is disabled.
100	pub struct rbtdre_Colors {
101	    pub green: &'static str,
102	    pub red: &'static str,
103	    pub yellow: &'static str,
104	    pub white: &'static str,
105	    pub reset: &'static str,
106	}
107	
108	/// Detect terminal color support from TERM environment variable.
109	pub fn rbtdre_detect_colors() -> rbtdre_Colors {
110	    match std::env::var("TERM") {
111	        Ok(term) if !term.is_empty() && term != "dumb" => rbtdre_Colors {
112	            green: "\x1b[1;32m",
113	            red: "\x1b[1;31m",
114	            yellow: "\x1b[1;33m",
115	            white: "\x1b[1;37m",
116	            reset: "\x1b[0m",
117	        },
118	        _ => rbtdre_Colors {
119	            green: "",
120	            red: "",
121	            yellow: "",
122	            white: "",
123	            reset: "",
124	        },
125	    }
126	}
127	
128	// ── Trace ──────────────────────────────────────────────────────
129	
130	/// Write verdict and detail to a trace file in the case temp directory.
131	fn rbtdre_write_trace(case_dir: &Path, display_name: &str, verdict: &rbtdre_Verdict) {
132	    let content = match verdict {
133	        rbtdre_Verdict::Pass => format!("PASSED: {}\n", display_name),
134	        rbtdre_Verdict::Fail(detail) => format!("FAILED: {}\n\n{}\n", display_name, detail),
135	        rbtdre_Verdict::Skip(reason) => {
136	            format!("SKIPPED: {}\n\nReason: {}\n", display_name, reason)
137	        }
138	    };
139	    let _ = std::fs::write(case_dir.join("trace.txt"), content);
140	}
141	
142	// ── Dispatch ───────────────────────────────────────────────────
143	
144	/// Aggregate results from running sections.
145	pub struct rbtdre_RunResult {
146	    pub passed: usize,
147	    pub failed: usize,
148	    pub skipped: usize,
149	    pub temp_dir: PathBuf,
150	}
151	
152	/// Run all sections sequentially, dispatching each case with per-case temp dir isolation.
153	pub fn rbtdre_run_sections(
154	    sections: &[rbtdre_Section],
155	    colors: &rbtdre_Colors,
156	    fail_fast: bool,
157	    root_temp: &Path,
158	) -> Result<rbtdre_RunResult, String> {
159	    let mut passed = 0usize;
160	    let mut failed = 0usize;
161	    let mut skipped = 0usize;
162	
163	    'outer: for section in sections {
164	        eprintln!(
165	            "\n{}--- {} ---{}",
166	            colors.white, section.name, colors.reset
167	        );
168	
169	        for case in section.cases {
170	            let case_dir = root_temp.join(case.name);
171	            std::fs::create_dir_all(&case_dir).map_err(|e| {
172	                format!("rbtd: failed to create case dir '{}': {}", case.name, e)
173	            })?;
174	
175	            let verdict = (case.func)(&case_dir);
176	            rbtdre_write_trace(&case_dir, case.name, &verdict);
177	
178	            match &verdict {
179	                rbtdre_Verdict::Pass => {
180	                    eprintln!("{}PASSED:{} {}", colors.green, colors.reset, case.name);
181	                    passed += 1;
182	                }
183	                rbtdre_Verdict::Fail(_) => {
184	                    eprintln!("{}FAILED:{} {}", colors.red, colors.reset, case.name);
185	                    failed += 1;
186	                    if fail_fast {
187	                        break 'outer;
188	                    }
189	                }
190	                rbtdre_Verdict::Skip(_) => {
191	                    eprintln!(
192	                        "{}SKIPPED:{} {}",
193	                        colors.yellow, colors.reset, case.name
194	                    );
195	                    skipped += 1;
196	                }
197	            }
198	        }
199	    }
200	
201	    Ok(rbtdre_RunResult {
202	        passed,
203	        failed,
204	        skipped,
205	        temp_dir: root_temp.to_path_buf(),
206	    })
207	}
208	
209	/// Print colored summary line and trace directory location.
210	pub fn rbtdre_print_summary(result: &rbtdre_RunResult, colors: &rbtdre_Colors) {
211	    let total = result.passed + result.failed + result.skipped;
212	    let (color, end_color) = if result.failed > 0 {
213	        (colors.red, colors.reset)
214	    } else {
215	        (colors.green, colors.reset)
216	    };
217	
218	    eprintln!(
219	        "\n{}{} passed, {} failed, {} skipped ({} total){}",
220	        color, result.passed, result.failed, result.skipped, total, end_color,
221	    );
222	    eprintln!("Trace dir: {}", result.temp_dir.display());
223	}
224	
225	// ── Single-case operations ───────────────────────────────────
226	
227	/// Find a case by name within sections.
228	pub fn rbtdre_find_case<'a>(
229	    sections: &'a [rbtdre_Section],
230	    target: &str,
231	) -> Option<&'a rbtdre_Case> {
232	    for section in sections {
233	        for case in section.cases {
234	            if case.name == target {
235	                return Some(case);
236	            }
237	        }
238	    }
239	    None
240	}
241	
242	/// List all cases grouped by section.
243	pub fn rbtdre_list_cases(sections: &[rbtdre_Section]) {
244	    for section in sections {
245	        eprintln!("\n--- {} ---", section.name);
246	        for case in section.cases {
247	            eprintln!("  {}", case.name);
248	        }
249	    }
250	}
251	
252	/// Run a single case without charge/quench lifecycle.
253	pub fn rbtdre_run_single_case(
254	    case: &rbtdre_Case,
255	    colors: &rbtdre_Colors,
256	    root_temp: &Path,
257	) -> Result<rbtdre_RunResult, String> {
258	    let case_dir = root_temp.join(case.name);
259	    std::fs::create_dir_all(&case_dir)
260	        .map_err(|e| format!("rbtd: failed to create case dir '{}': {}", case.name, e))?;
261	
262	    let verdict = (case.func)(&case_dir);
263	    rbtdre_write_trace(&case_dir, case.name, &verdict);
264	
265	    let (passed, failed, skipped) = match &verdict {
266	        rbtdre_Verdict::Pass => {
267	            eprintln!("{}PASSED:{} {}", colors.green, colors.reset, case.name);
268	            (1, 0, 0)
269	        }
270	        rbtdre_Verdict::Fail(_) => {
271	            eprintln!("{}FAILED:{} {}", colors.red, colors.reset, case.name);
272	            (0, 1, 0)
273	        }
274	        rbtdre_Verdict::Skip(_) => {
275	            eprintln!("{}SKIPPED:{} {}", colors.yellow, colors.reset, case.name);
276	            (0, 0, 1)
277	        }
278	    };
279	
280	    Ok(rbtdre_RunResult {
281	        passed,
282	        failed,
283	        skipped,
284	        temp_dir: root_temp.to_path_buf(),
285	    })
286	}
