16	//
17	// RBTDRF — fast-tier test cases for theurge
18	//
19	// Ports enrollment-validation (47), regime-validation (21), and regime-smoke (7)
20	// from bash test framework to theurge. Cases shell out to bash — theurge invokes
21	// the actual bash utilities and asserts on exit codes. No reimplementation.
22	
23	use std::path::Path;
24	use std::process::Command;
25	
26	use crate::case;
27	use crate::rbtdre_engine::{rbtdre_Section, rbtdre_Verdict};
28	use crate::rbtdri_invocation::rbtdri_find_tabtarget_global;
29	
30	// ── Helpers ──────────────────────────────────────────────────
31	
32	/// Sub-assertion within a case: run bash snippet, check exit code.
33	struct RbtdrfSub {
34	    label: &'static str,
35	    setup: &'static str,
36	    command: &'static str,
37	    expect_ok: bool,
38	}
39	
40	impl RbtdrfSub {
41	    const fn ok(label: &'static str, setup: &'static str) -> Self {
42	        Self { label, setup, command: "buv_vet \"TEST\"", expect_ok: true }
43	    }
44	    const fn fatal(label: &'static str, setup: &'static str) -> Self {
45	        Self { label, setup, command: "buv_vet \"TEST\"", expect_ok: false }
46	    }
47	    const fn ok_cmd(label: &'static str, setup: &'static str, command: &'static str) -> Self {
48	        Self { label, setup, command, expect_ok: true }
49	    }
50	    const fn fatal_cmd(label: &'static str, setup: &'static str, command: &'static str) -> Self {
51	        Self { label, setup, command, expect_ok: false }
52	    }
53	}
54	
55	/// Run a bash script, return (exit_code, stdout, stderr). Saves traces to case dir.
56	fn rbtdrf_run_bash(
57	    project_root: &Path,
58	    script: &str,
59	    dir: &Path,
60	    trace_prefix: &str,
61	) -> Result<(i32, String, String), String> {
62	    let output = Command::new("bash")
63	        .arg("-c")
64	        .arg(script)
65	        .current_dir(project_root)
66	        .output()
67	        .map_err(|e| format!("bash execution failed: {}", e))?;
68	
69	    let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
70	    let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
71	    let code = output.status.code().unwrap_or(-1);
72	
73	    let _ = std::fs::write(dir.join(format!("{}-script.sh", trace_prefix)), script);
74	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", trace_prefix)), &stdout);
75	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", trace_prefix)), &stderr);
76	
77	    Ok((code, stdout, stderr))
78	}
79	
80	/// Run enrollment-validation sub-assertions against BUV.
81	fn rbtdrf_run_ev(
82	    dir: &Path,
83	    enrollment: &str,
84	    subs: &[RbtdrfSub],
85	) -> rbtdre_Verdict {
86	    let root = match std::env::current_dir() {
87	        Ok(r) => r,
88	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
89	    };
90	    let buv = root.join("Tools/buk/buv_validation.sh");
91	
92	    for (i, sub) in subs.iter().enumerate() {
93	        let script = format!(
94	            "set -euo pipefail\nsource '{}'\nzbuv_kindle\nzbuv_reset_enrollment\n{}\n{}\n{}",
95	            buv.display(),
96	            enrollment,
97	            sub.setup,
98	            sub.command,
99	        );
100

